INSERT INTO `db_payment_methods` (`id`, `shop_id`, `name`, `code`, `description`, `logo`, `fee_type`, `fee_value`, `api_config`, `is_active`, `sort_order`, `created_at`, `updated_at`, `id_code`, `lang`) VALUES
(1, 0, 'Thanh toán khi nhận hàng (COD)', 'cash-on-delivery', '<p>Kh&aacute;ch h&agrave;ng sẽ thanh to&aacute;n tiền mặt trực tiếp cho nh&acirc;n vi&ecirc;n giao h&agrave;ng khi nhận được sản phẩm. Phương thức n&agrave;y gi&uacute;p kh&aacute;ch h&agrave;ng y&ecirc;n t&acirc;m kiểm tra h&agrave;ng trước khi trả tiền, ph&ugrave; hợp với những người kh&ocirc;ng c&oacute; t&agrave;i khoản ng&acirc;n h&agrave;ng hoặc chưa quen thanh to&aacute;n online.</p>\r\n', NULL, 'fixed', '0.00', NULL, 1, 0, '2026-06-19 09:14:25', '2026-06-19 19:58:43', 1, 'vi'),
(2, 0, 'Chuyển khoản ngân hàng', 'bank-transfer', '<p>Kh&aacute;ch h&agrave;ng sử dụng Internet Banking, Mobile Banking hoặc ra quầy giao dịch để chuyển tiền v&agrave;o t&agrave;i khoản ng&acirc;n h&agrave;ng của doanh nghiệp. Đơn h&agrave;ng sẽ được hệ thống tự động hoặc thủ c&ocirc;ng x&aacute;c nhận v&agrave; xử l&yacute; sau khi tiền b&aacute;o về.</p>\r\n', NULL, 'fixed', '0.00', NULL, 1, 1, '2026-06-19 10:20:26', '2026-06-19 19:58:43', 2, 'vi'),
(3, 0, 'Cash on delivery (COD)', 'cash-on-delivery', '', NULL, 'fixed', '0.00', NULL, 1, 0, '2026-06-19 19:14:08', '2026-06-19 19:58:43', 1, 'en'),
(4, 0, 'Bank Transfer', 'bank-transfer', '', NULL, 'fixed', '0.00', NULL, 1, 1, '2026-06-19 19:15:54', '2026-06-19 19:58:43', 2, 'en'),
(5, 0, 'Thẻ tín dụng / Ghi nợ quốc tế (Visa, Mastercard, JCB)', 'credit-debit-card', '<p>Kh&aacute;ch h&agrave;ng thanh to&aacute;n nhanh ch&oacute;ng qua cổng thanh to&aacute;n trực tuyến (Payment Gateway) bằng c&aacute;ch nhập th&ocirc;ng tin thẻ Visa, Mastercard hoặc JCB. Giao dịch được bảo mật bằng m&atilde; h&oacute;a SSL/3D Secure v&agrave; tiền được trừ trực tiếp v&agrave;o hạn mức thẻ.</p>\r\n', '', 'fixed', '0.00', NULL, 1, 0, '2026-06-19 20:09:12', '2026-06-19 20:09:12', 5, 'vi'),
(6, 0, 'International credit/debit cards (Visa, Mastercard, JCB)', 'credit-debit-card', '', '', 'fixed', '0.00', NULL, 1, 0, '2026-06-19 20:09:12', '2026-06-19 20:09:12', 5, 'en');
